import { Button, HStack,Input } from "@chakra-ui/react";
import { Field, Form, Formik } from "formik";
import * as Yup from "yup";

 const ChatBox=()=>{
   return <Formik initialValues={{message:""}}  
   validationSchema={Yup.object({
    message:Yup.string().min(1).max(255),
   })}
   onSubmit={(values,actions)=>{
    console.log(values.message);
      actions.resetForm();
   }}
   >
      <HStack as={Form} w="100%" pb="1.4rem" px="1.4rem"> 
       <Input as={Field}  name="message" placeholder="Type Message ..." size="lg" autoComplete="off"></Input>

       <Button type="submit" size="lg"colorScheme="teal" >Send</Button>   

      </HStack>
   </Formik>
 };

export default ChatBox
